import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"AgentOps","description":"","frontmatter":{},"headers":[],"relativePath":"agentops/index.md","filePath":"agentops/index.md","lastUpdated":1783462857000}'),n={name:"agentops/index.md"};function o(r,e,l,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="agentops" tabindex="-1">AgentOps <a class="header-anchor" href="#agentops" aria-label="Permalink to &quot;AgentOps&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Documentation in progress</p><p>This page is an early outline. Full AgentOps documentation is still being written and will be added here.</p></div><p>AgentOps is the prokube product track for building and operating AI agents on controlled infrastructure.</p><p>It combines governed model access, tool access, memory, isolated code execution, and observability into one platform track. The goal is to let teams run agents without giving them uncontrolled credentials, unmanaged SaaS dependencies, or direct access to sensitive infrastructure.</p><h2 id="core-capabilities" tabindex="-1">Core Capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core Capabilities&quot;">​</a></h2><ul><li><strong>Agent Gateway</strong> for public API routes, scoped API keys, routing, and policy enforcement.</li><li><strong>Agent Sandboxes</strong> for isolated code execution in Kubernetes-native environments.</li><li><strong>MCP Servers</strong> for exposing tools, skills, and internal APIs as governed capabilities.</li><li><strong>Memory Stores</strong> for agent state and retrieval-backed workflows.</li><li><strong>Agents</strong> for managed agent runtimes, skills, tools, and agent-to-agent patterns.</li></ul><h2 id="shared-platform-services" tabindex="-1">Shared Platform Services <a class="header-anchor" href="#shared-platform-services" aria-label="Permalink to &quot;Shared Platform Services&quot;">​</a></h2><p>AgentOps uses the same foundation as the MLOps track:</p><ul><li>Workspaces and identity</li><li>Role-based access control</li><li>Observability and audit trails</li><li>Object storage and persistent volumes</li><li>GitOps-managed operations</li><li>Kubernetes-native resource isolation</li></ul><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><p>The AgentOps feature set is under active integration. Some components are already used in pilot deployments, while the final installer profile and public documentation structure are still being shaped.</p>',11)])])}const m=t(n,[["render",o]]);export{g as __pageData,m as default};
